mapper.insert:
		/*
             SQL ID : OnlnMeetngrmDAO.onlnMeetngrmRegist
             설  명 : 온라인회의실등록
         */
         INSERT INTO TB_LMS_ONLN_MEETNGRM (
	     	  ONLN_MEETNGRM_ID
			, ONLN_PLTFRM_USER_ID
			, SMNR_ID
			, MEETNGRM_URL
			, MEETNGRM_ID
			, MEETNGRM_SDTTM
			, MEETNGRM_EDTTM
			, MEETNGRM_PSWD
			, MEETNGRM_UUID
			, RGTR_ID
			, REG_DTTM
	     ) VALUES (
	     	  #{onlnMeetngrmId}
			, #{onlnPltfrmUserId}
			, #{smnrId}
			, #{meetngrmUrl}
			, #{meetngrmId}
			, #{meetngrmSdttm}
			, #{meetngrmEdttm}
			, #{meetngrmPswd}
			, #{meetngrmUuid}
			, #{rgtrId}
			, FN_DTTM()
	     )

mapper.update:
		/*
             SQL ID : OnlnMeetngrmDAO.onlnMeetngrmModify
             설  명 : 온라인회의실수정
         */
        UPDATE TB_LMS_ONLN_MEETNGRM SET
        	  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
			, MEETNGRM_SDTTM = #{meetngrmSdttm}
			, MEETNGRM_EDTTM = #{meetngrmEdttm}
		 WHERE SMNR_ID = #{smnrId}

mapper.delete:
		/*
             SQL ID : OnlnMeetngrmDAO.onlnMeetngrmDelete
             설  명 : 온라인회의실삭제
         */
        DELETE FROM TB_LMS_ONLN_MEETNGRM
         WHERE SMNR_ID = #{smnrId}
           AND MEETNGRM_ID = #{meetngrmId}
